13→public class FunctionTypeReferenceSpacingRule : StandardRule("function-type-reference-spacing") {
14→    override fun beforeVisitChildNodes(
15→        node: ASTNode,
16→        autoCorrect: Boolean,
17→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
18→    ) {
19→        if (node.elementType == FUN) {
20→            node
21→                .findFunctionReceiverTypeReference()
22→                ?.let { typeReference ->
23→                    typeReference
24→                        .firstChildNode
25→                        .takeIf { it.elementType == NULLABLE_TYPE }
26→                        ?.let { nullableTypeElement ->
27→                            visitNodesUntilStartOfValueParameterList(nullableTypeElement.firstChildNode, emit, autoCorrect)
28→                        }
29→
30→                    if (typeReference.elementType != NULLABLE_TYPE) {
31→                        visitNodesUntilStartOfValueParameterList(typeReference, emit, autoCorrect)
32→                    }
33→                }
34→        }
35→    }
36→
37→    private fun ASTNode.findFunctionReceiverTypeReference(): ASTNode? {
38→        require(elementType == FUN)
39→        var currentNode: ASTNode? = firstChildNode
40→        while (currentNode != null && currentNode.elementType != VALUE_PARAMETER_LIST) {
41→            if (currentNode.elementType == TYPE_REFERENCE) {
42→                return currentNode
43→            }
44→            currentNode = currentNode.nextSibling()
45→        }
46→        return null
47→    }
48→
49→    private fun visitNodesUntilStartOfValueParameterList(
50→        node: ASTNode,
51→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
52→        autoCorrect: Boolean,
53→    ) {
54→        var currentNode: ASTNode? = node
55→        while (currentNode != null && currentNode.elementType != VALUE_PARAMETER_LIST) {
56→            val nextNode = currentNode.nextSibling()
57→            removeIfNonEmptyWhiteSpace(currentNode, emit, autoCorrect)
58→            currentNode = nextNode
59→        }
60→    }
61→
62→    private fun removeIfNonEmptyWhiteSpace(
63→        node: ASTNode,
64→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
65→        autoCorrect: Boolean,
66→    ) {
67→        if (node.elementType == WHITE_SPACE && node.text.isNotEmpty()) {
68→            emit(node.startOffset, "Unexpected whitespace", true)
69→            if (autoCorrect) {
70→                node.treeParent.removeChild(node)
71→            }
72→        }
73→    }
74→}
